mapper.select:
SELECT FROM ai_seo_metrics_snapshots
AND site_id = #{siteId}
ORDER BY snapshot_date DESC

mapper.update:
UPDATE ai_seo_metrics_snapshots
indexed_pages = #{indexedPages}, avg_position = #{avgPosition}, clicks = #{clicks}, impressions = #{impressions}, ctr = #{ctr}, metrics_json = #{metricsJson}::jsonb, site_id = site_id
WHERE id = #{id}
